  // 木部
  { char: "概", words: ["大概", "概念", "概況"], zhuyin: "ㄍㄞˋ", pinyin: "gài", radical: "木" },
  { char: "構", words: ["結構", "構成", "建構"], zhuyin: "ㄍㄡˋ", pinyin: "gòu", radical: "木" },
  { char: "模", words: ["模型", "模仿", "模範"], zhuyin: "ㄇㄛˊ", pinyin: "mó", radical: "木" },
  { char: "標", words: ["標準", "目標", "標題"], zhuyin: "ㄅㄧㄠ", pinyin: "biāo", radical: "木" },
  { char: "樸", words: ["樸實", "純樸", "樸素"], zhuyin: "ㄆㄨˇ", pinyin: "pǔ", radical: "木" },
  { char: "檢", words: ["檢查", "檢討", "檢驗"], zhuyin: "ㄐㄧㄢˇ", pinyin: "jiǎn", radical: "木" },
  { char: "植", words: ["植物", "種植", "植樹"], zhuyin: "ㄓˊ", pinyin: "zhí", radical: "木" },
  { char: "棉", words: ["棉花", "棉被", "棉布"], zhuyin: "ㄇㄧㄢˊ", pinyin: "mián", radical: "木" },
  { char: "楓", words: ["楓葉", "楓樹", "楓林"], zhuyin: "ㄈㄥ", pinyin: "fēng", radical: "木" },
  { char: "榮", words: ["光榮", "榮譽", "榮幸"], zhuyin: "ㄖㄨㄥˊ", pinyin: "róng", radical: "木" },
  // 水部
  { char: "源", words: ["來源", "資源", "水源"], zhuyin: "ㄩㄢˊ", pinyin: "yuán", radical: "水" },
