// ─── Utility ───────────────────────────────────────────────────────────
function shuffle(arr) {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

function pickRandom(arr, n, exclude = []) {
  const filtered = arr.filter(x => !exclude.includes(x));
  return shuffle(filtered).slice(0, n);
}

// ─── App Component ─────────────────────────────────────────────────────
export default function HanziApp() {
  const [screen, setScreen] = useState("home"); // home | browse | quiz | import | history
  const [mode, setMode] = useState(null);

  const [timeLimit, setTimeLimit] = useState(180);
  const [timeLeft, setTimeLeft] = useState(0);
  const [isTimerRunning, setIsTimerRunning] = useState(false);
  const [questionStartTime, setQuestionStartTime] = useState(0);
  const [responseTimes, setResponseTimes] = useState([]);
  const timerRef = useRef(null);

  const [history, setHistory] = useState(() => {
    try {
      const saved = localStorage.getItem("hanziHistory");
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  // ─── Custom Data & LocalStorage Logic ───
  const [customData, setCustomData] = useState(() => {
    try {
      const saved = localStorage.getItem("customHanzi");
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  const [importText, setImportText] = useState("");

  const hanziData = useMemo(() => {
    return [...DEFAULT_HANZI_DATA, ...customData];
  }, [customData]);

  const allRadicals = useMemo(() => {
    return [...new Set(hanziData.map(h => h.radical))];
  }, [hanziData]);

  const [selectedRadicals, setSelectedRadicals] = useState(new Set(allRadicals));

  // 當題庫有變化時（例如匯入新字），自動將新部首加入已選清單中
  useEffect(() => {
    setSelectedRadicals(new Set(allRadicals));
  }, [allRadicals]);

  // ─── Quiz States ───
  const [quizPool, setQuizPool] = useState([]);
  const [currentIdx, setCurrentIdx] = useState(0);
  const [options, setOptions] = useState([]);
  const [selected, setSelected] = useState(null);
  const [correct, setCorrect] = useState(null);
  const [score, setScore] = useState(0);
  const [total, setTotal] = useState(0);
  const [showResult, setShowResult] = useState(false);
  const [browseRadical, setBrowseRadical] = useState(allRadicals[0]);
  const [flipCard, setFlipCard] = useState(null);
  const [wordBlank, setWordBlank] = useState(null);
  const [streak, setStreak] = useState(0);
  const [bestStreak, setBestStreak] = useState(0);
  const [animKey, setAnimKey] = useState(0);

  const filteredData = hanziData.filter(h => selectedRadicals.has(h.radical));

  // ─── Timer Logic ───
  const endQuiz = useCallback(() => {
    setIsTimerRunning(false);
    setShowResult(true);
  }, []);

  useEffect(() => {
    if (screen === "quiz" && !showResult && isTimerRunning && timeLimit > 0) {
      timerRef.current = setInterval(() => {
        setTimeLeft(prev => {
          if (prev <= 1) {
            clearInterval(timerRef.current);
            endQuiz();
            return 0;
          }
          return prev - 1;
        });
      }, 1000);
    }
    return () => clearInterval(timerRef.current);
  }, [screen, showResult, isTimerRunning, timeLimit, endQuiz]);

  useEffect(() => {
    if (showResult && screen === "quiz") {
      setHistory(prev => {
        if (prev.length > 0 && prev[0].date && (Date.now() - new Date(prev[0].date).getTime() < 2000)) {
          return prev;
        }
        const newHistory = { date: new Date().toISOString(), mode, timeLimit, score, total };
        const updatedHistory = [newHistory, ...prev].slice(0, 100);
        localStorage.setItem("hanziHistory", JSON.stringify(updatedHistory));
        return updatedHistory;
      });
    }
  }, [showResult, screen, mode, timeLimit, score, total]);

  const topSlowest = useMemo(() => {
    if (responseTimes.length === 0) return [];
    const charTimes = {};
    responseTimes.forEach(rt => {
      if (!charTimes[rt.char]) charTimes[rt.char] = { sum: 0, count: 0 };
      charTimes[rt.char].sum += rt.time;
      charTimes[rt.char].count += 1;
    });
    const avgTimes = Object.keys(charTimes).map(char => ({
      char,
      avgTime: charTimes[char].sum / charTimes[char].count
    }));
    avgTimes.sort((a, b) => b.avgTime - a.avgTime);
    return avgTimes.slice(0, 5);
  }, [responseTimes]);

  // ─── Import Functions ───
  const handleImport = () => {
    if (!importText.trim()) return alert("請輸入內容！");

    const lines = importText.split("\n");
    const newItems = [];

    for (const line of lines) {
      const trimmed = line.trim();
      if (!trimmed) continue;

      let parts = [];
      const isMdTable = trimmed.startsWith('|') && trimmed.endsWith('|');

      if (isMdTable) {
        parts = trimmed.split('|').map(s => s.trim()).filter(s => s);
        // 略過標題列與分隔線
        if (parts.length === 0 || parts[0] === '漢字' || parts[0].includes('---')) continue;
      } else {
        parts = trimmed.split(",").map(s => s.trim());
      }

      // 確保格式符合：漢字,注音,拼音,造詞1/造詞2,部首
      if (parts.length >= 4) {
        newItems.push({
          char: parts[0],
          zhuyin: parts[1],
          pinyin: parts[2],
          words: parts[3].split("/").map(w => w.trim()).filter(w => w),
          radical: parts[4] || "自訂"
        });
      }
    }

    if (newItems.length === 0) {
      return alert("格式不正確或沒有可匯入的單字。請確認格式為：漢字,注音,拼音,造詞1/造詞2,部首 (或使用 Markdown 表格)");
    }

    const updatedCustom = [...customData, ...newItems];
    setCustomData(updatedCustom);
    localStorage.setItem("customHanzi", JSON.stringify(updatedCustom));
    setImportText("");
    alert(`成功匯入 ${newItems.length} 個單字！`);
    setScreen("home");
  };

  const handleClearCustom = () => {
    if (window.confirm("確定要清除所有自訂單字嗎？")) {
      setCustomData([]);
      localStorage.removeItem("customHanzi");
      alert("自訂題庫已清除！");
    }
  };

  // ─── Quiz Functions ───
  const startQuiz = (m) => {
    if (filteredData.length < 3) {
      return alert("題庫字數太少，請至少勾選包含 3 個字以上的部首！");
    }
    const pool = shuffle(filteredData);
    setMode(m);
    setQuizPool(pool);
    setCurrentIdx(0);
    setScore(0);
    setTotal(0);
    setSelected(null);
    setCorrect(null);
    setShowResult(false);
    setStreak(0);
    setBestStreak(0);
    setScreen("quiz");
    setResponseTimes([]);
    setTimeLeft(timeLimit);
    setIsTimerRunning(true);
    generateQuestion(pool, 0, m);
  };

  const generateQuestion = useCallback((pool, idx, m) => {
    const currentPoolIdx = idx % pool.length;
    let activePool = pool;
    if (idx > 0 && currentPoolIdx === 0) {
      activePool = shuffle([...pool]);
      setQuizPool(activePool);
    }
    const item = activePool[currentPoolIdx];
    setAnimKey(k => k + 1);
    setQuestionStartTime(Date.now());

    if (m === 1) {
      const wrongs = pickRandom(hanziData.map(h => h.zhuyin), 2, [item.zhuyin]);
      setOptions(shuffle([item.zhuyin, ...wrongs]));
    } else if (m === 2) {
      const wrongs = pickRandom(hanziData.map(h => h.char), 2, [item.char]);
      setOptions(shuffle([item.char, ...wrongs]));
    } else if (m === 3) {
      const word = item.words[Math.floor(Math.random() * item.words.length)];
      if (word) {
        const charIdx = word.indexOf(item.char);
        const blanked = charIdx !== -1
          ? word.substring(0, charIdx) + "＿" + word.substring(charIdx + 1)
          : "＿" + word.substring(1); // fallback
        setWordBlank(blanked);
      } else {
        setWordBlank("＿");
      }
      const wrongs = pickRandom(hanziData.map(h => h.char), 2, [item.char]);
      setOptions(shuffle([item.char, ...wrongs]));
    }
    setSelected(null);
    setCorrect(null);
  }, [hanziData]);

  const handleSelect = (opt) => {
    if (selected !== null) return;
    const item = quizPool[currentIdx % quizPool.length];
    let isCorrect;
    if (mode === 1) isCorrect = opt === item.zhuyin;
    else if (mode === 2) isCorrect = opt === item.char;
    else isCorrect = opt === item.char;

    const timeSpent = Date.now() - questionStartTime;
    setResponseTimes(prev => [...prev, { char: item.char, time: timeSpent }]);

    setSelected(opt);
    setCorrect(isCorrect);
    if (isCorrect) {
      setScore(s => s + 1);
      setStreak(s => {
        const ns = s + 1;
        setBestStreak(b => Math.max(b, ns));
        return ns;
      });
    } else {
      setStreak(0);
    }
    setTotal(t => t + 1);

    setTimeout(() => {
      const next = currentIdx + 1;
      setCurrentIdx(next);
      generateQuestion(quizPool, next, mode);
    }, 1200);
  };

  const toggleRadical = (r) => {
    setSelectedRadicals(prev => {
      const next = new Set(prev);
      if (next.has(r)) next.delete(r);
      else next.add(r);
      return next;
    });
  };

  const selectAll = () => setSelectedRadicals(new Set(allRadicals));
  const clearAll = () => setSelectedRadicals(new Set());

  // 確保瀏覽部首存在，若無則切回第一個
  const currentBrowseRadical = allRadicals.includes(browseRadical) ? browseRadical : allRadicals[0];
  const browseCards = hanziData.filter(h => h.radical === currentBrowseRadical);

  // ─── Styles ──────────────────────────────────────────────────────────
  const css = `
    @import url('https://fonts.googleapis.com/css2?family=Noto+Serif+TC:wght@600;900&display=swap');

    @font-face {
