      --accent2: #e74c3c;
      --gold: #d4a017;
      --jade: #1a8a5c;
      --jade-light: #2ecc71;
      --cloud: #ecf0f1;
      --mist: #dfe6e9;
      --shadow: rgba(26, 26, 46, 0.08);
      --correct: #27ae60;
