    .btn-primary { padding: 12px 28px; border-radius: 999px; border: none; background: var(--accent); color: white; font-family: inherit; font-size: 1.1rem; font-weight: 600; cursor: pointer; transition: all 0.2s; }
    .btn-primary:hover { background: var(--accent2); transform: translateY(-2px); }
    .btn-secondary { padding: 12px 28px; border-radius: 999px; border: 2px solid var(--ink); background: white; color: var(--ink); font-family: inherit; font-size: 1.1rem; font-weight: 600; cursor: pointer; transition: all 0.2s; }
    .btn-secondary:hover { background: var(--ink); color: white; }

    .streak-badge { display: inline-flex; align-items: center; gap: 4px; padding: 4px 12px; background: linear-gradient(135deg, #ff9a56, #ff6b6b); color: white; border-radius: 999px; font-size: 0.9rem; animation: streakPop 0.3s ease; }
    @keyframes streakPop { 0% { transform: scale(0.8); } 50% { transform: scale(1.15); } 100% { transform: scale(1); } }
  `;

  // ─── Render ──────────────────────────────────────────────────────────
  return (
    <>
      <style>{css}</style>
      <div className="app">
        {/* ═══ HOME ═══ */}
        {screen === "home" && (
          <>
            <div className="header">
              <h1>漢字高手</h1>
              <div className="subtitle">內建 {DEFAULT_HANZI_DATA.length} 字 + 自訂 {customData.length} 字</div>
            </div>

            <div style={{ display: 'flex', gap: '8px', justifyContent: 'center', margin: '16px 0', flexWrap: 'wrap' }}>
              {[180, 300, 900, 0].map(t => (
                <button 
                  key={t}
                  className="btn-secondary"
                  onClick={() => setTimeLimit(t)}
                  style={{
                    padding: '8px 16px',
                    fontSize: '0.95rem',
                    background: timeLimit === t ? 'var(--ink)' : 'white',
                    color: timeLimit === t ? 'white' : 'var(--ink)'
                  }}
                >
                  {t === 0 ? "無限(自行暫停)" : `${t / 60} 分鐘`}
                </button>
              ))}
              <button 
                className="btn-secondary" 
                onClick={() => setScreen("history")}
                style={{ padding: '8px 16px', fontSize: '0.95rem', borderColor: 'var(--accent)', color: 'var(--accent)' }}
              >
                🏆 時間成績表
              </button>
            </div>

            <div className="home-grid">
              <div className="mode-card" onClick={() => setScreen("browse")}>
                <span className="mode-tag tag-dark">瀏覽</span>
                <div className="mode-icon">📖</div>
                <h3>字卡瀏覽</h3>
                <p>按部首分類瀏覽所有漢字，含注音、拼音與造詞</p>
              </div>

              <div className="mode-card" onClick={() => startQuiz(1)}>
                <span className="mode-tag tag-red">測驗一</span>
                <div className="mode-icon">👀</div>
                <h3>看漢字 → 選注音</h3>
                <p>看到漢字，從三個注音中選出正確的讀音</p>
              </div>

              <div className="mode-card" onClick={() => startQuiz(2)}>
                <span className="mode-tag tag-green">測驗二</span>
                <div className="mode-icon">👂</div>
                <h3>看注音 → 選漢字</h3>
                <p>看到注音，從三個漢字中選出正確的字</p>
              </div>

              <div className="mode-card" onClick={() => startQuiz(3)}>
                <span className="mode-tag tag-gold">測驗三</span>
                <div className="mode-icon">✏️</div>
                <h3>造詞填空</h3>
                <p>詞語中缺一個字，從三個漢字中選出正確的填入</p>
              </div>

              <div className="mode-card" onClick={() => setScreen("import")}>
                <span className="mode-tag tag-purple">進階</span>
                <div className="mode-icon">➕</div>
                <h3>擴充自訂題庫</h3>
                <p>將生字表或課本重點字大量匯入題庫中</p>
              </div>
            </div>

            <div className="radical-section">
              <h4>
                目前篩選字數 <span className="count-badge">{filteredData.length}/{hanziData.length}</span>
                <span className="chip-actions">
                  <button onClick={selectAll}>全選</button>
                  <button onClick={clearAll}>清除</button>
                </span>
              </h4>
              <div className="radical-chips">
                {allRadicals.map(r => (
                  <span
                    key={r}
                    className={`radical-chip ${selectedRadicals.has(r) ? "on" : ""}`}
                    onClick={() => toggleRadical(r)}
                  >
                    {r}部
                  </span>
                ))}
              </div>
            </div>
          </>
        )}

        {/* ═══ IMPORT SCREEN ═══ */}
        {screen === "import" && (
          <>
            <div className="header" style={{ position: "relative" }}>
              <button className="back-btn" onClick={() => setScreen("home")}>←</button>
              <h1>匯入自訂字庫</h1>
            </div>

            <div className="import-card">
              <p>您可以輸入 CSV 格式或 <b>Markdown 表格</b>，造詞用斜線 <code>/</code> 分開。</p>
              <div className="import-code" style={{ marginBottom: '8px' }}>
                <strong>CSV 格式：</strong><br/>
                漢字,注音,拼音,造詞1/造詞2,部首<br />
                學,ㄒㄩㄝˊ,xué,學校/學習,子<br />
              </div>
              <div className="import-code">
                <strong>MD 表格格式：</strong><br/>
                | 漢字 | 注音 | 拼音 | 造詞 | 部首 |<br/>
                |---|---|---|---|---|<br/>
                | 習 | ㄒㄧˊ | xí | 習慣/練習 | 羽 |
              </div>

              <textarea
                className="import-textarea"
                placeholder="在此貼上您的字表..."
                value={importText}
                onChange={(e) => setImportText(e.target.value)}
              />

              <button className="btn-primary" style={{ width: "100%" }} onClick={handleImport}>
                確認匯入
              </button>

              <div className="import-stats">
                <span>目前已自訂 {customData.length} 個字</span>
                {customData.length > 0 && (
                  <button className="btn-danger" onClick={handleClearCustom}>清除所有自訂</button>
                )}
              </div>
            </div>
          </>
        )}

        {/* ═══ BROWSE ═══ */}
        {screen === "browse" && (
          <>
            <div className="header" style={{ position: "relative" }}>
              <button className="back-btn" onClick={() => setScreen("home")}>←</button>
              <h1>字卡瀏覽</h1>
            </div>

            <div className="browse-tabs">
              {allRadicals.map(r => (
                <button
                  key={r}
                  className={`browse-tab ${currentBrowseRadical === r ? "active" : ""}`}
                  onClick={() => { setBrowseRadical(r); setFlipCard(null); }}
                >
                  {r}部
                </button>
              ))}
            </div>

            <div className="card-grid">
              {browseCards.map((h, i) => (
                <div
                  key={h.char}
                  className={`char-card ${flipCard === i ? "flipped" : ""}`}
                  onClick={() => setFlipCard(flipCard === i ? null : i)}
                >
                  <div className="big-char">{h.char}</div>
                  <div className="card-zhuyin">{h.zhuyin}</div>
                  <div className="card-pinyin">{h.pinyin}</div>
                  <div className="card-words">{h.words.join("、")}</div>
                </div>
              ))}
            </div>
          </>
        )}

        {/* ═══ QUIZ ═══ */}
        {screen === "quiz" && !showResult && quizPool.length > 0 && (
          <>
            <div className="header" style={{ position: "relative" }}>
              <button className="back-btn" onClick={() => { setIsTimerRunning(false); setScreen("home"); }}>←</button>
              <h1>
                {mode === 1 ? "看字選音" : mode === 2 ? "看音選字" : "造詞填空"}
              </h1>
            </div>

            <div className="quiz-header">
              <span className="quiz-progress" style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                {timeLimit > 0 ? (
                  <strong style={{ color: timeLeft <= 10 ? 'var(--wrong)' : 'var(--ink)', fontSize: '1.1rem' }}>
                    ⏱ {Math.floor(timeLeft / 60)}:{(timeLeft % 60).toString().padStart(2, '0')}
                  </strong>
                ) : (
                  <button className="btn-secondary" style={{ padding: '4px 12px', fontSize: '0.85rem' }} onClick={endQuiz}>結束測驗</button>
                )}
                <span>已答 {total} 題</span>
              </span>
              <div className="quiz-score">
                {streak >= 2 && (
                  <span className="streak-badge" key={streak}>🔥 {streak} 連對</span>
                )}
                <span className="score-item">✓ {score}</span>
              </div>
            </div>

            {timeLimit > 0 && (
              <div className="progress-bar">
                <div className="progress-fill" style={{ width: `${(timeLeft / timeLimit) * 100}%` }} />
              </div>
            )}

            <div className="quiz-card" key={animKey}>
              {mode === 1 && (
                <>
                  <div className="prompt-label">這個字怎麼念？</div>
                  <div className="prompt-char">{quizPool[currentIdx % quizPool.length].char}</div>
                  <div className="hint-text">{quizPool[currentIdx % quizPool.length].pinyin}</div>
                </>
              )}
              {mode === 2 && (
                <>
                  <div className="prompt-label">這個注音是哪個字？</div>
                  <div className="prompt-zhuyin">{quizPool[currentIdx % quizPool.length].zhuyin}</div>
                  <div className="hint-text">{quizPool[currentIdx % quizPool.length].pinyin}</div>
                </>
              )}
              {mode === 3 && (
                <>
                  <div className="prompt-label">請選出正確的字填入空格</div>
                  <div className="prompt-word">{wordBlank}</div>
                  <div className="hint-text">{quizPool[currentIdx % quizPool.length].zhuyin} · {quizPool[currentIdx % quizPool.length].pinyin}</div>
                </>
              )}
            </div>

            <div className="options-grid">
              {options.map((opt, i) => {
                const item = quizPool[currentIdx % quizPool.length];
                const correctAnswer = mode === 1 ? item.zhuyin : item.char;
                let cls = "option-btn";
                if (selected !== null) {
                  cls += " disabled";
                  if (opt === selected && correct) cls += " correct-opt";
                  else if (opt === selected && !correct) cls += " wrong-opt";
                  else if (opt === correctAnswer && !correct) cls += " reveal-correct";
                }
                return (
                  <button key={i} className={cls} onClick={() => handleSelect(opt)}>
                    {opt}
                  </button>
                );
              })}
            </div>
          </>
        )}

        {/* ═══ RESULT ═══ */}
        {screen === "quiz" && showResult && (
          <>
            <div className="header" style={{ position: "relative" }}>
              <button className="back-btn" onClick={() => setScreen("home")}>←</button>
              <h1>測驗結果</h1>
            </div>

            <div className="result-card">
              <div className="result-emoji">
                {total === 0 ? "📚" : (score / total) >= 0.9 ? "🏆" : (score / total) >= 0.7 ? "🌟" : (score / total) >= 0.5 ? "💪" : "📚"}
              </div>
              <h2>
                {total === 0 ? "沒有作答紀錄" : (score / total) >= 0.9 ? "太厲害了！" : (score / total) >= 0.7 ? "表現很好！" : (score / total) >= 0.5 ? "繼續加油！" : "多練習幾次吧！"}
              </h2>
              <div className="result-score">{score} / {total}</div>
              <div className="result-detail">
                正確率 {total > 0 ? Math.round((score / total) * 100) : 0}%
                {bestStreak >= 2 && ` · 最高連對 ${bestStreak} 題`}
              </div>

              {topSlowest.length > 0 && (
                <div style={{ background: 'var(--paper)', padding: '16px', borderRadius: '12px', margin: '24px 0', textAlign: 'left' }}>
                  <h4 style={{ color: 'var(--ink)', marginBottom: '12px', fontSize: '1.05rem', fontFamily: "'Noto Serif TC', serif" }}>⏱ 思考最久的 5 個字</h4>
                  {topSlowest.map((ts, i) => (
                    <div key={i} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '8px 0', borderBottom: i < topSlowest.length - 1 ? '1px solid var(--mist)' : 'none' }}>
                      <strong style={{ fontSize: '1.4rem', color: 'var(--accent)', fontFamily: "'Noto Serif TC', serif" }}>{ts.char}</strong>
                      <span style={{ color: '#666', fontSize: '0.95rem' }}>{(ts.avgTime / 1000).toFixed(1)} 秒/次</span>
                    </div>
                  ))}
                </div>
              )}

              <div className="result-actions">
                <button className="btn-primary" onClick={() => startQuiz(mode)}>再來一次</button>
                <button className="btn-secondary" onClick={() => setScreen("home")}>回首頁</button>
              </div>
            </div>
          </>
        )}

        {/* ═══ HISTORY SCORECARD ═══ */}
        {screen === "history" && (
          <>
            <div className="header" style={{ position: "relative" }}>
              <button className="back-btn" onClick={() => setScreen("home")}>←</button>
              <h1>時間成績表</h1>
            </div>

            <div style={{ marginTop: '24px' }}>
              {history.length === 0 ? (
                <p style={{ textAlign: 'center', color: '#888', padding: '32px 0' }}>尚無測驗紀錄</p>
              ) : (
                history.map((record, i) => (
                  <div key={i} style={{ background: 'white', padding: '16px 20px', borderRadius: '16px', marginBottom: '12px', border: '2px solid var(--cloud)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <div>
                      <div style={{ fontSize: '0.9rem', color: '#888', marginBottom: '4px' }}>
                        {new Date(record.date).toLocaleString([], { year: 'numeric', month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' })}
                      </div>
                      <div style={{ color: 'var(--ink)', fontWeight: 'bold' }}>
                        模式 {record.mode} · {record.timeLimit === 0 ? '無限時間' : `${record.timeLimit / 60} 分鐘`}
                      </div>
                    </div>
                    <div style={{ textAlign: 'right' }}>
                      <div style={{ fontSize: '1.5rem', fontWeight: '900', color: 'var(--accent)', fontFamily: "'Noto Serif TC', serif" }}>
                        {record.score} <span style={{ fontSize: '1rem', color: '#aaa' }}>/ {record.total}</span>
                      </div>
                      <div style={{ fontSize: '0.85rem', color: '#666' }}>
                        正確率 {record.total > 0 ? Math.round((record.score / record.total) * 100) : 0}%
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          </>
        )}
      </div>
    </>
  );
}
